// app/layout.tsx
'use client';
import * as React from 'react';
import { ThemeProvider, CssBaseline, createTheme, Box, Container } from '@mui/material';

const theme = createTheme();

export default function RootLayout({ children }: { children: React.ReactNode }) {
  // state drawer มือถือถ้าจะต่อยอด (ตอนนี้ Header แสดงเฉพาะมือถือแล้ว)
  const [openMobile, setOpenMobile] = React.useState(false);

  return (
    <html lang="th">
      <body>
        <ThemeProvider theme={theme}>
          <CssBaseline />
          <Header title="Dashboard" onMenuClick={() => setOpenMobile(true)} />

          <Box sx={{ display: 'flex', minHeight: '100dvh', bgcolor: 'background.default' }}>
            <SideMenu currentPath="/" />

            <Box
              component="main"
              sx={{
                flex: 1,
                mt: { xs: '64px', md: 0 }, // กันทับ AppBar บนมือถือ (สูง ~64px)
                p: { xs: 2, md: 3 },
              }}
            >
              <Container maxWidth="lg">{children}</Container>
            </Box>
          </Box>
        </ThemeProvider>
      </body>
    </html>
  );
}